package ru.memearena.tournament.domain; import jakarta.persistence.*; import java.time.*; import java.util.*; @Entity @Table(name="meme_tournament_stats") public class MemeTournamentStats{ @Id @Column(name="meme_id") public UUID memeId; public long participations; public long finals; public long wins; @Column(name="updated_at") public Instant updatedAt; protected MemeTournamentStats(){} public MemeTournamentStats(UUID id,Instant now){memeId=id;updatedAt=now;} }
